{
  "name": "Minnesota Senior Health Options (MSHO)",
  "eligibility": {
    "age": 65,
    "income_limits": "No specific dollar amounts or household size table provided in sources; eligibility requires enrollment in Medical Assistance (Medicaid), which has its own income and asset limits not detailed here. MSHO follows MA eligibility criteria.",
    "asset_limits": "No specific asset limits or exemptions detailed in sources; follows Medical Assistance (Medicaid) asset rules, which are not specified.",
    "other_requirements": [
      "Must be eligible for and enrolled in Medical Assistance (MA/Medicaid), with or without Medicare.",
      "If Medicare-eligible, must have both Medicare Part A and Part B.",
      "Minnesota resident.",
      "Live in a county where an MSHO health plan is offered.",
      "Voluntary enrollment; no functional eligibility criteria for base program, but some services (e.g., personal care assistance) require demonstrated need in one Activity of Daily Living (ADL) or qualifying behavior."
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Combines Medicare (Parts A and B) and Medicaid (Medical Assistance) services into one managed care plan, including: doctors, hospital care, pharmacies, home care, nursing home care (180 days if entering from community; not covered if already in facility at enrollment), elderly waiver services, personal care assistance, in-home care, transportation, preventive care (e.g., $0 cost wellness visits, cancer screenings, shots), specialist care ($0 cost). Care coordinator assigned to help access services. Additional long-term services via 1915(c) Elderly Waiver.",
    "varies_by": "region"
  },
  "application": {
    "methods": [
      "Phone: Call Minnesota Department of Human Services Health Care Consumer Support (HCCS) at 1-651-297-3862 or 1-800-657-3672 for choice counseling; or specific plans like Blue Cross SecureBlue at 1-866-477-1584 or (651) 662-1811, TTY 711.",
      "Enroll through health plans offering MSHO (e.g., Medica DUAL Solution, UCare, Blue Cross SecureBlue, South Country Health Alliance SeniorCare Complete).",
      "Ensure prior MA/Medicaid eligibility."
    ],
    "processing_time": "Not specified in sources.",
    "waitlist": null,
    "forms": [],
    "documents": [
      "Proof of age (65+), Medicare Parts A and B enrollment (if applicable), Medical Assistance eligibility, residency in service area county."
    ]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Available only in counties where a health plan offers MSHO (see DHS map of MSHO health plans by county). Examples include Aitkin, Anoka, Becker, Benton, Blue Earth (for UCare).",
    "regional_variations": "Offered by different health plans (e.g., Medica, UCare, Blue Cross MN SecureBlue, South Country Health Alliance) in specific counties; different providers and service areas by plan.",
    "offices_or_providers": [
      "Administered by MN DHS and seven health plans; check county-specific plans via DHS."
    ]
  },
  "official_source": "https://mn.gov/dhs/people-we-serve/seniors/health-care/health-care-programs/programs-and-services/msho.jsp",
  "gotchas": [
    "Nursing facility services not covered by MSHO if resident on enrollment effective date (MCO pays for 180 days only if entering from community).",
    "Must have both Medicare Part A and B if Medicare-eligible; voluntary, but non-enrollees age 65+ may be mandatorily enrolled in alternative like Minnesota Senior Care Plus (MSC+).",
    "Some services require prior authorization or functional need (e.g., ADLs for personal care).",
    "Enrollment depends on health plan contract renewal and service area.",
    "Prior MA eligibility required; apply for MA first if not enrolled."
  ],
  "data_shape_notes": "County-restricted to areas with offering health plans; dual Medicare-Medicaid managed care with long-term services via Elderly Waiver; no base functional criteria but service-specific needs; varies by provider/plan."
}

{
  "name": "Low Income Home Energy Assistance Program (LIHEAP) / Energy Assistance",
  "eligibility": {
    "age": null,
    "income_limits": "Annual gross income limits for 10/1/2025 to 9/30/2026: 1 person $37,439; 2 people $48,959; 3 people $60,479; 4 people $71,999; 5 people $83,518; 6 people $95,038; 7 people $97,198. Limits for larger households available from Minnesota Department of Commerce. Monthly equivalents: 1 $3,743; 2 $4,895; 3 $6,047; 4 $7,199; 5 $8,351; 6 $9,503.[1][2]",
    "asset_limits": "No asset limits mentioned in available sources.",
    "other_requirements": ["Must live in Minnesota.", "Household includes everyone at the address covered by the same utility bill.", "Renters and homeowners both qualify.", "Must meet income guidelines based on 50% of State Median Income (SMI)."][2][3][5]
  },
  "benefits": {
    "type": "financial",
    "value": "Regular (Primary Heat) benefit: one-time payment to utility company, max $1,400 heating, min $200. Crisis: Winter max $600, Summer not available. Amount varies by household income, size, fuel type, and heating costs.[1][4]",
    "varies_by": "household_size|priority_tier|region"
  },
  "application": {
    "methods": ["Online: https://energy-assistance.web.commerce.state.mn.us", "Phone: 1-800-657-3710 or 651-296-2860 (TTY)", "Mail or in-person: Local Energy Assistance Provider (find via phone or state site)", "Download application form and submit to local provider."[2][5]],
    "processing_time": "Within a month of applying.[2]",
    "waitlist": "Funding limited; agencies may stop accepting applications if funds run out before deadlines.[1][4]",
    "forms": ["Energy Assistance Program application (download from local provider or state site). No specific form number listed.[2]"],
    "documents": ["Proof of income over past 3 months.", "Name of heating/electric provider and account number.", "Most recent energy bills."][2]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Must live in Minnesota; apply through local EAP agency.",
    "regional_variations": "Administered by local Energy Assistance providers, which may have different processing times, availability, or fuel considerations.[4]",
    "offices_or_providers": ["Local EAP agencies (contact via 1-800-657-3710 to find yours)."][2][4]
  },
  "official_source": "https://mn.gov/commerce/consumer/energy-utilities/apply-energy-assistance/index.jsp",
  "gotchas": ["Funding limited; apply early as agencies may close applications before May 31, 2026 deadline.", "Household includes all at address on utility bill (e.g., roommates count).", "Program year Oct 1-May 31; separate crisis assistance dates.", "No interview or immigration proof required.", "Benefits paid directly to utility, not household."[1][2][4]],
  "data_shape_notes": "Income-based at 50% SMI, varies by household size/fuel; local providers handle applications with potential early fund exhaustion; no asset test or age requirement."
}

{
  "name": "Weatherization Assistance Program (WAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Based on the greater of 200% of Federal Poverty Income Guidelines (effective January 17, 2024) or LIHEAP income limit of 50% of State Median Income (effective October 1, 2024). Uses previous calendar month (or past three months per some providers) of household income. 2025 Energy Assistance Program guidelines (aligned with WAP): |Household Size|1 Month Max|Annual Income| |1|$2,983|$35,799| |2|$3,901|$46,814| |3|$4,819|$57,829| |4|$5,737|$68,845| |5|$6,655|$79,860| |6|$7,572|$90,875| Households receiving TANF or SSI within the last 12 months are eligible regardless of income.[1][2][3][5]",
    "asset_limits": "No asset limits mentioned in available sources.",
    "other_requirements": ["Must apply through or qualify for Energy Assistance Program (EAP) for the current program year.", "Home must not have received weatherization services in the past 15 years.", "Available to both homeowners and renters.", "Priority given to households with elderly or disabled members, children under 19, high energy consumers/burden."][1][2][3][4][6]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-time energy-saving home upgrades including caulking, weather-stripping, reducing air infiltration, attic insulation, heating unit tune-ups and modifications. Free home energy assessment to identify improvements. No cost to recipient; grant-funded.[1][6]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Combined application for Energy Assistance Program (EAP) and Weatherization Assistance: online via local provider sites or state links, phone (800) 657-3710, email energy.info@state.mn.us, mail to local Community Action Partnership (CAP) agency, in-person pickup at local providers.", "Some providers require additional Weatherization Interest Form (PDF).", "Contact local CAP via map or MN Dept. of Commerce Energy Information Center at 1-800-657-3710 or energy.info@state.mn.us to find provider.", "Provider-specific: e.g., MN Valley Action Council link to applications; Semcac mail to local; UCAP online interest form."[1][2][3][4][5]],
    "processing_time": "Varies by local provider after eligibility determination; no statewide timeline specified.",
    "waitlist": "Yes, eligible households placed on waiting list; wait time varies between local service providers.[1][2][4][5]",
    "forms": ["Combined Energy Assistance and Weatherization Assistance application.", "Weatherization Interest Form (some providers like UCAP)."][2][3][4],
    "documents": ["Proof of household income for previous calendar month (or past three months).", "Proof of TANF/SSI if applicable.", "Proof of residency/ownership or rental agreement.", "Energy Assistance application documents (income verification, ID). Specifics determined by local provider."][1][2][5]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered through local Community Action Partnerships (CAPs) or Tribal nations; find provider by county/map.",
    "regional_variations": "Different local providers by county/region (e.g., Minnesota Valley Action Council, Semcac serves Dodge/Fillmore/Freeborn/Houston/Mower/Steele/Winona; UCAP serves Cottonwood/Jackson/Kandiyohi/Lincoln/Lyon/Meeker/McLeod/Renville/Redwood/Rock/Nobles/Pipestone/Murray). Wait times, applications, and processing vary by provider.[1][2][3][4]",
    "offices_or_providers": ["Local CAP agencies; use map or call 1-800-657-3710 to locate by county."][3][5]
  },
  "official_source": "https://mn.gov/commerce/consumer/energy-utilities/weatherization/index.jsp",
  "gotchas": ["Must first qualify/apply for Energy Assistance Program (EAP); WAP often tied to it.", "Home ineligible if weatherized in past 15 years.", "One-time service only.", "Priority tiers mean elderly households get preference but still face waitlists.", "Different local providers by county; organization for WAP may differ from EAP processor.", "Wait times vary significantly by region/provider.", "Contractor qualifications strict (lead certification, etc.), may affect service speed."[1][2][3][4]],
  "data_shape_notes": "Administered by county-specific CAP providers with varying waitlists and forms; eligibility tied to EAP income guidelines and 15-year repeat restriction; priority for elderly but no strict age cutoff."
}

{
  "name": "Senior Health Insurance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to all Medicare-eligible individuals (typically age 65+, or younger with disabilities), their family members, and caregivers, including those with limited incomes or dually eligible for Medicare and Medicaid[2][3][6].",
    "asset_limits": "No asset limits or tests apply[2][3].",
    "other_requirements": ["Must be Medicare-eligible or a family member/caregiver of a Medicare beneficiary[2][6]", "Reside in Minnesota[4]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Free, personalized one-on-one counseling and education on Medicare (Parts A, B, C, D), Medigap, Medicare Advantage plans, Medicare Savings Programs, Extra Help/Low-Income Subsidy, Medicaid, long-term care insurance, prescription drug assistance, appeals of denied claims, managing medical bills, and protection from fraud/errors/abuse via Senior Medicare Patrol (SMP); also includes referrals, printed materials, public presentations, and enrollment assistance[2][3][5][6]. No direct financial aid, healthcare services, or fixed dollar amounts/hours provided.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Senior LinkAge Line at 800-333-2433 (statewide toll-free)[4][6]", "Website: mnship.org or shiphelp.org for local counselors and appointments[6][8]", "In-person or phone counseling appointments via local SHIP sites (over 2,200 nationally, coordinated through Minnesota Board on Aging)[3][4]"],
    "processing_time": "Immediate counseling available by phone or appointment; no formal enrollment or processing as it's a free counseling service[6].",
    "waitlist": null,
    "forms": ["No specific forms required; contact for appointment[6]"],
    "documents": ["Medicare card, health insurance details, medical bills/statements (if applicable for counseling); no documents needed for initial contact[6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide in Minnesota[4]",
    "regional_variations": "Delivered through local network of over 2,200 sites partnering with area agencies on aging and community organizations; counselors located county-wide but no specified differences in services, wait times, or providers by region[3][4][5].",
    "offices_or_providers": ["Minnesota Board on Aging, 540 Cedar Street, P.O. Box 64976, St. Paul, MN 55164-0976 (state office); local sites via Senior LinkAge Line[4]"]
  },
  "official_source": "https://mn.gov/dhs/people-we-serve/seniors/health-care/health-care-programs/programs-and-services/ (DHS page) or https://shiphelp.org (national SHIP locator); state contact via CMS: Minnesota SHIP/Senior LinkAge Line[4][7]",
  "gotchas": ["Not a health insurance or direct benefit program—provides only free counseling and advocacy, not coverage or payments[2][6]", "Counselors are unbiased and do not sell insurance; cannot provide legal advice but offer referrals[2][5]", "Often confused with Minnesota Senior Health Options (MSHO), which is a managed care insurance program for MA/Medicare dually eligible seniors age 65+[1][7]", "Services for Medicare beneficiaries under 65 with disabilities also available[3]"],
  "data_shape_notes": "no income test; counseling-only advocacy service delivered via statewide volunteer/staff network; distinct from insurance programs like MSHO"
}

{
  "name": "Family Adult Caregiver Support Program",
  "eligibility": {
    "age": 60,
    "income_limits": "No specific income limits detailed in available sources; eligibility tied to Minnesota's Medicaid programs like Elderly Waiver or Minnesota Senior Health Options, which generally require low income (e.g., seniors often limited to ~$2,982/month for HCBS waivers or $994-$1,330/month for regular Medicaid in 2026, but exact household size tables not specified for this program)[4]",
    "asset_limits": "$2,000 asset limit typical for Medicaid-related senior programs in Minnesota (e.g., HCBS waivers); countable assets generally include bank accounts, investments; exemptions often include primary home, one vehicle, personal belongings (details vary by program assessment)[4]",
    "other_requirements": ["Caregiver must be adult family member or informal caregiver for individual 60+ or with Alzheimer's (any age)", "Care recipient must be enrolled in Medicaid, Elderly Waiver, or Minnesota Senior Health Options", "Caregiver at least 18 (exceptions for 16-17 with supervision)", "Pass criminal background check", "Complete state-required training and certification", "Care recipient must demonstrate need for care"]
  },
  "benefits": {
    "type": "service",
    "value": "Support services including caregiver skills classes, individual consulting, self-directed grants, limited respite care, information/referral; transitioned to Community First Services and Supports (CFSS) as of Oct 1, 2024, providing flexible home care assistance (e.g., personal care) with greater consumer control; no fixed dollar amounts or hours specified, varies by assessed need",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Minnesota Aging Pathways at 800-333-2433 (Mon-Fri 8am-4:30pm)", "Through licensed provider agency for CFSS/PCA enrollment", "Online classes/counseling available when in-person not possible"],
    "processing_time": "Funds often 1-3 business days post-approval for some payments, but full assessment/reassessment varies; transition to CFSS at next annual reassessment",
    "waitlist": "Not specified; may exist based on regional demand",
    "forms": ["DHS-3238 (related brochure for some caregivers, but not primary)", "PCA/CFSS enrollment forms via DHS or agency"],
    "documents": ["Proof of Medicaid/Elderly Waiver enrollment", "Background check completion", "Training/certification records", "Documentation of care need and relationship"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered statewide via Minnesota Board on Aging and DHS, but services through local providers",
    "regional_variations": "Delivered via regional Area Agencies on Aging; wait times, providers, and availability may vary by county/region; contact local office for specifics",
    "offices_or_providers": ["Minnesota Aging Pathways (statewide helpline)", "Licensed provider agencies for CFSS"]
  },
  "official_source": "https://mn.gov/board-on-aging/connect-to-services/family-caregiving/",
  "gotchas": ["Program transitioned from PCA to CFSS as of Oct 1, 2024—existing recipients auto-transition at reassessment unless condition changes", "Must go through licensed agency and DHS enrollment; family can't be paid independently", "Not direct cash payment to caregivers but service support/grants; compare to Medicaid self-direction (CFSS) for payment option", "Living arrangement rules may apply in related programs", "Background checks and training mandatory—often overlooked"],
  "data_shape_notes": "Tied to national NFCSP framework but Minnesota-specific via Board on Aging; benefits via local AAAs with CFSS integration; no strict income table but Medicaid-linked; statewide with regional delivery"
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
