    "income_limits": "Family income no more than 125% of the federal poverty level. Exact dollar amounts vary annually and by household size; consult current federal poverty guidelines via USDOL or local provider for table (e.g., for 2023, 125% for 1-person household was ~$18,825, but verify latest as not specified in sources)[4][5]",
    "asset_limits": null,
    "other_requirements": ["Unemployed", "Limited job prospects", "Minnesota resident (some providers specify county, e.g., Hennepin for certain grantees)", "Priority: Veterans and qualified spouses first, then over 65, disability, low literacy, limited English, rural resident, homeless/at risk, low employment prospects, or failed American Job Center services[4][5]"]
  },
  "benefits": {
    "type": "employment",
    "value": "Part-time community service work-based job training averaging 20 hours/week at nonprofit, school, government, hospital, senior center, or daycare sites; paid highest of federal, state, or local minimum wage; skills development for unsubsidized employment; access to American Job Centers[1][2][4][5][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["State central: https://mn.gov/deed/programs-services/dislocated-worker/scsep/index.jsp (MN DEED)[1]", "MET Inc.: https://www.metinc.org/senior-employment-program (metro area)[2]", "Minnesota Valley Action Council: senior@mnvac.org, 507-345-6822, in-person 706 N Victory Dr., Mankato, MN; online SCSEP Application form (Blue Earth, Brown, Faribault, Martin, Nicollet, Watonwan counties)[6]", "CWI Works (grantee): Check https://www.cwiworks.org/for-job-seekers/our-programs/scsep/scsep-near-you/scsep-in-minnesota/ for local sub-grantees[5][8]", "East Side Neighborhood Services (Hennepin County, prior operator; contact for current)[3]", "Phone/website via grantees or American Job Centers"],
    "processing_time": null,
    "waitlist": "Possible due to funding limits and priority enrollment; varies by region and provider (not specified quantitatively)[3]",
    "forms": ["SCSEP Application (e.g., via MNVAC)[6]"],
    "documents": ["Proof of age (ID)", "Proof of income (pay stubs, tax returns)", "Proof of unemployment", "Proof of residency (some providers)", "Veteran status if applicable (not explicitly listed but implied for priority)"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide via grantees/sub-grantees, but some county-specific (e.g., MNVAC: Blue Earth, Brown, Faribault, Martin, Nicollet, Watonwan; Hennepin via prior ESNS)[3][6]",
    "regional_variations": "Operated by different grantees/sub-grantees (e.g., CWI Works, MET Inc., MNVAC); availability, wait times, worksites vary by region (urban vs. rural focus)[2][5][6][8]",
    "offices_or_providers": ["MN DEED (state admin)", "MET Inc.", "Minnesota Valley Action Council (south-central counties)", "CWI Works sub-grantees", "Former: East Side Neighborhood Services (Hennepin)"]
  },
  "official_source": "https://mn.gov/deed/programs-services/dislocated-worker/scsep/index.jsp",
  "gotchas": ["Not permanent employment—temporary training bridge to unsubsidized jobs[1][4]", "Strict priority tiers may delay non-priority applicants[4][5]", "County-specific providers mean checking local grantee for eligibility/availability[3][6]", "Income at exactly 125% FPL cutoff; excludes employed individuals[1][4]", "Furloughs or sponsor changes possible (e.g., ESNS ended sponsorship)[3]", "No asset test mentioned, but prove low income rigorously"],
  "data_shape_notes": "Grantee/sub-grantee model with regional providers; income tied to federal poverty levels (no fixed MN table in sources); priority enrollment creates wait variations; 20hr/wk minimum wage training only, not direct aid"
}

{
  "name": "Legal Assistance for Seniors (LAS)",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict income limits or dollar amounts for seniors; available to people of any income level age 60 or older, with focus on those with greatest social and economic need. Low-income individuals also qualify regardless of age in some programs. Financial eligibility based on Federal Poverty Guidelines for general clients, but seniors exempt from means test.[2][3][4][6]",
    "asset_limits": "No asset limits or tests mentioned for seniors; providers may ask about financial circumstances only for advice or identifying benefits, not as condition for services.[3][7]",
    "other_requirements": ["Minnesota resident", "Civil legal issues only (no criminal, personal injury, or cases with damages awarded)", "Case must be venued in the service area of the specific legal aid provider (e.g., 21 counties for Central MN, specific counties for others)", "Priority on economic/social needs, elder abuse, public benefits, housing, etc."][1][2][5][6]
  },
  "benefits": {
    "type": "service",
    "value": "Civil legal services including advice, consultation, representation, brief services (e.g., document preparation), pro se assistance, litigation, administrative representation. Specific areas: elder abuse, public benefits (food support, cash assistance, Social Security, Medical Assistance, home care), housing/evictions, debt collection, nursing home discharges, disability cases, domestic violence, wills clinics (powers of attorney, health care directives, transfer on death deeds). Provided by licensed attorneys in-person, phone, or electronic.[2][3][4][5][6]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online intake/application at https://mylegalaid.org/get-legal-help or provider-specific sites", "Phone: (877) 696-6529 (main intake, Justice North/Mid-MN), (800) 292-4150 (MN Disability Law Center), local offices e.g., (612) 332-4668 or (612) 334-5970 (Minneapolis)", "Call local office for in-person or mail referrals", "Complete intake to determine eligibility"],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": ["Online intake/application form (asks for household info, income, assets, legal issue)"],
    "documents": ["Proof of income/household size if applicable (for general eligibility screening), details of legal issue/case location. Specific documents not listed; prepare during intake call."][1][7]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Limited to counties served by each regional legal aid provider (e.g., Mid-Minnesota Legal Aid: Anoka, Hennepin; Central MN Legal Services: 21 counties; Southern MN Regional Legal Services: southern areas; Justice North: northern areas)",
    "regional_variations": "Services delivered by regional providers (e.g., Mid-Minnesota Legal Aid Senior Law Project in Minneapolis, Southern Minnesota Regional Legal Services); different offices, phone numbers, focus areas; referrals between providers if outside service area.[1][5][6]",
    "offices_or_providers": ["Mid-Minnesota Legal Aid (Minneapolis: 111 N 5th St, Ste 100, Minneapolis, MN 55403)", "Central Minnesota Legal Services (21 counties)", "Southern Minnesota Regional Legal Services", "Justice North"]
  },
  "official_source": "https://www.dhs.state.mn.us/main/idcplg?IdcService=GET_DYNAMIC_CONVERSION&dDocName=MNDHS-068891&RevisionSelectionMethod=LatestReleased",
  "gotchas": ["Not statewide—must check county/service area and get referral if outside; no criminal/personal injury cases; seniors exempt from income test but priority to greatest need; complete intake to confirm eligibility as guidelines vary by provider; Title III providers cannot require income disclosure as condition.[1][2][3][8]"],
  "data_shape_notes": "Delivered via regional legal aid nonprofits under Title III (no means test for seniors 60+), county-restricted service areas, priority-based allocation to greatest economic/social need"
}

{
