    "processing_time": "Not specified in available data",
    "waitlist": null,
    "forms": [],
    "documents": ["No specific documents required; contact for complaint or information, provide details about the issue or facility[2][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Program operates statewide with regional ombudsmen offices and volunteers serving specific areas (e.g., Dan Tupy, Regional Ombudsman at 11600 State Ave., Brainerd, MN 56401, serving Benton, Kanabec, Mille Lacs, Pope, Sherburne, Stearns, and Todd counties); access points may vary by region but core services are uniform[3]",
    "offices_or_providers": ["Central office: P.O. Box 64971, St. Paul, MN 55164-0971[7]", "Example regional: 11600 State Ave., Brainerd, MN 56401[3]"]
