}

{
  "name": "Minnesota Senior Care Plus",
  "eligibility": {
    "age": 65,
    "income_limits": "Must qualify for Medical Assistance (Medicaid). For Elderly, Blind and Disabled Medicaid (effective 7/1/25 – 6/30/26): $1,305/month for single applicant; $1,764/month for married couples (regardless if one or both apply). Equivalent to 100% Federal Poverty Level, updated annually (income limits increase July for MN Medicaid).[1]",
    "asset_limits": "Standard Medical Assistance asset limits apply (not specified in sources; check current MN DHS rules). Home ownership considered in financial criteria.[1]",
    "other_requirements": ["Minnesota resident", "Eligible for Medical Assistance (Medicaid)", "May or may not have Medicare Parts A & B (unlike MSHO which requires both)", "Live in a county served by an MSC+ health plan (varies by provider)"][1][2][3]
  },
